SELECT A.NMOBILE_IP_COMMU_SEQ -- 무선_IP_COMMUNITY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.SCOMMUNITY -- COMMUNITY , A.PIP_PREFIX -- IP 블록 , A.SSERVICE_NM -- 서비스명 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.NMOBILE_IP_COMMU_SEQ -- 무선_IP_COMMUNITY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.SCOMMUNITY -- COMMUNITY , A.PIP_PREFIX -- IP 블록 , A.SSERVICE_NM -- 서비스명 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT A.NMOBILE_IP_COMMU_SEQ -- 무선_IP_COMMUNITY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , NVL(A.SCOMMUNITY, '-') AS SCOMMUNITY -- COMMUNITY , NVL(CAST(A.PIP_PREFIX AS VARCHAR), '-') AS PIP_PREFIX -- IP 블록 , A.SSERVICE_NM -- 서비스명 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_MOBILE_IP_COMMU_MST A -- 무선IP_사전_정보관리 WHERE 1=1
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND A.SCOMMUNITY ILIKE '%' || #{scommu, jdbcType=VARCHAR} || '%'
AND (A.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL))
AND A.SSERVICE_NM ILIKE '%' || #{sserviceNm, jdbcType=VARCHAR} || '%'
ORDER BY A.NMOBILE_IP_COMMU_SEQ ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT A.NMOBILE_IP_COMMU_SEQ -- 무선_IP_COMMUNITY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.SCOMMUNITY -- COMMUNITY , A.PIP_PREFIX -- IP 블록 , A.SSERVICE_NM -- 서비스명 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_MOBILE_IP_COMMU_MST A -- 무선IP_사전_정보관리 WHERE 1=1
AND A.NMOBILE_IP_COMMU_SEQ != #{nmobileIpCommuSeq, jdbcType=BIGINT}
AND A.SKIND_CD = 'COMMU' AND A.SCOMMUNITY = #{scommu, jdbcType=VARCHAR}
AND A.SKIND_CD = 'NOCOMMU' AND A.PIP_PREFIX = #{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}

mapper.insert:
INSERT
INTO MST.TB_MOBILE_IP_COMMU_MST (
	SKIND_CD  -- 구분_코드
	,   SKIND_NM  -- 구분_명
	,   SCOMMUNITY  -- COMMUNITY
	,   PIP_PREFIX  -- IP 블록
	,   SSERVICE_NM	  -- 서비스명
	,	SCREATE_ID
	,	SMODIFY_ID

) VALUES (
	#{skindCd, jdbcType=VARCHAR}
	,	#{skindNm, jdbcType=VARCHAR}
	,	#{scommu, jdbcType=VARCHAR}
	,	#{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
	,	#{sserviceNm, jdbcType=VARCHAR}
	,	#{screateId, jdbcType=VARCHAR}
	,	#{smodifyId, jdbcType=VARCHAR}
)

mapper.update:
UPDATE
	MST.TB_MOBILE_IP_COMMU_MST A
SET
	A.DMODIFY_DT = SYSDATE

		, A.SCOMMUNITY = #{scommu, jdbcType=VARCHAR}


		, A.PIP_PREFIX = #{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.SSERVICE_NM = #{sserviceNm, jdbcType=VARCHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

WHERE 1=1
	AND A.NMOBILE_IP_COMMU_SEQ = #{nmobileIpCommuSeq, jdbcType=BIGINT}
